export class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private lastRefill: number;

  constructor(maxTokens: number, refillRate: number) {
    this.maxTokens = maxTokens;
    this.tokens = maxTokens;
    this.refillRate = refillRate;
    this.lastRefill = Date.now();
  }

  tryConsume(): boolean {
    this.refill();
    if (this.tokens >= 1) {
      this.tokens -= 1;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefill = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefill;
    const newTokens = (elapsed * this.refillRate) / 1000;
    this.tokens = Math.min(this.tokens + newTokens, this.maxTokens);
    this.lastRefill = now;
  }
}

export interface Record {
  id: number;
  name: string;
  category: string;
  value: number;
}

export type Stage = (records: Record[]) => Record[];
export type Filter = (record: Record) => boolean;

export class Pipeline {
  private stages: Stage[] = [];
  private filters: Filter[] = [];

  addStage(stage: Stage): this {
    this.stages.push(stage);
    return this;
  }

  addFilter(filter: Filter): this {
    this.filters.push(filter);
    return this;
  }

  run(records: Record[]): Record[] {
    let result = [...records];
    if (this.filters.length > 0) {
      result = result.filter((r) => this.filters.every((f) => f(r)));
    }
    for (const stage of this.stages) {
      result = stage(result);
    }
    return result;
  }
}

export function andFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.every((f) => f(record));
}

export function orFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.some((f) => f(record));
}

export function notFilter(filter: Filter): Filter {
  return (record: Record) => !filter(record);
}

export function doubleValues(records: Record[]): Record[] {
  return records.map((r) => ({ ...r, value: r.value * 2 }));
}

export interface CronSchedule {
  minutes: number[];
  hours: number[];
  daysOfMonth: number[];
  months: number[];
  daysOfWeek: number[];
  original: string;
}

export class CronParseError extends Error {
  constructor(message: string, public field?: string) {
    super(message);
    this.name = 'CronParseError';
  }
}

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(value: string, min: number, max: number, fieldName: string): number[] {
  const validate = (n: number) => {
    if (n < min || n > max) {
      throw new CronParseError(`Value ${n} out of range [${min}-${max}] for field "${fieldName}"`, fieldName);
    }
    return n;
  };

  const parseNum = (s: string): number => {
    const n = parseInt(s, 10);
    if (isNaN(n) || s.trim() !== String(n)) {
      throw new CronParseError(`Invalid value "${s}" in field "${fieldName}"`, fieldName);
    }
    return n;
  };

  if (value.includes(',')) {
    const parts = value.split(',');
    const values: number[] = [];
    for (const part of parts) {
      const subValues = parseField(part, min, max, fieldName);
      values.push(...subValues);
    }
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (value.includes('/')) {
    const [rangePart, stepStr] = value.split('/');
    const step = parseNum(stepStr);
    if (step <= 0) throw new CronParseError(`Step must be positive in field "${fieldName}"`, fieldName);

    let start: number;
    let end: number;

    if (rangePart === '*') {
      start = min;
      end = max;
    } else if (rangePart.includes('-')) {
      const [startStr, endStr] = rangePart.split('-');
      start = validate(parseNum(startStr));
      end = validate(parseNum(endStr));
      if (start > end) throw new CronParseError(`Invalid range ${rangePart} in field "${fieldName}"`, fieldName);
    } else {
      start = validate(parseNum(rangePart));
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  if (value.includes('-')) {
    const [startStr, endStr] = value.split('-');
    const start = validate(parseNum(startStr));
    const end = validate(parseNum(endStr));
    if (start > end) throw new CronParseError(`Invalid range ${value} in field "${fieldName}"`, fieldName);
    return range(start, end);
  }

  if (value === '*') {
    return range(min, max);
  }

  return [validate(parseNum(value))];
}

export function parseCron(expression: string): CronSchedule {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new CronParseError(`Expected 5 fields but got ${fields.length}`);
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;

  return {
    minutes: parseField(minuteStr, 0, 59, 'minute'),
    hours: parseField(hourStr, 0, 23, 'hour'),
    daysOfMonth: parseField(domStr, 1, 31, 'day-of-month'),
    months: parseField(monthStr, 1, 12, 'month'),
    daysOfWeek: parseField(dowStr, 0, 6, 'day-of-week'),
    original: expression,
  };
}

export interface Item {
  id: string;
  name: string;
  status: "active" | "archived";
  createdAt: number;
  updatedAt: number;
}

export interface Request {
  method: "GET" | "POST" | "PUT" | "DELETE" | string;
  headers: Record<string, string>;
  params: Record<string, string>;
  body?: unknown;
}

export interface Response {
  status: number;
  body: unknown;
}

const store = new Map<string, Item>();

export function resetStore(): void {
  store.clear();
}

export function getStore(): Map<string, Item> {
  return store;
}

function ok(data: unknown, status = 200): Response {
  return { status, body: { success: true, data } };
}

function err(status: number, error: string): Response {
  return { status, body: { success: false, error } };
}

function checkAuth(req: Request): Response | null {
  if (!req.headers["authorization"]) return err(401, "Authorization required");
  if (req.headers["authorization"] !== "Bearer valid-token") return err(401, "Invalid token");
  return null;
}

function requireBody(req: Request): Response | null {
  if (!req.body) return err(400, "Request body is required");
  return null;
}

function requireId(req: Request): Response | null {
  if (!req.params["id"]) return err(400, "Validation failed: id parameter is required");
  return null;
}

function handleGet(req: Request): Response {
  if (!req.params["id"]) return ok(Array.from(store.values()));
  const item = store.get(req.params["id"]);
  return item ? ok(item) : err(404, "Item not found");
}

function handlePost(req: Request): Response {
  const bodyErr = requireBody(req);
  if (bodyErr) return bodyErr;
  const data = req.body as Record<string, unknown>;
  if (!data["name"] || typeof data["name"] !== "string") {
    return err(400, "Validation failed: name is required");
  }
  const id = data["id"] as string | undefined;
  if (id && store.has(id)) return err(409, "Item already exists");
  const newId = id || `item-${Date.now()}`;
  const now = Date.now();
  const item: Item = { id: newId, name: data["name"], status: "active", createdAt: now, updatedAt: now };
  store.set(newId, item);
  return ok(item, 201);
}

function handlePut(req: Request): Response {
  const bodyErr = requireBody(req);
  if (bodyErr) return bodyErr;
  const idErr = requireId(req);
  if (idErr) return idErr;
  const item = store.get(req.params["id"]);
  if (!item) return err(404, "Item not found");
  const data = req.body as Record<string, unknown>;
  const updated: Item = { ...item, updatedAt: Date.now() };
  if (data["name"] && typeof data["name"] === "string") updated.name = data["name"];
  if (data["status"] === "active" || data["status"] === "archived") updated.status = data["status"];
  store.set(req.params["id"], updated);
  return ok(updated);
}

function handleDelete(req: Request): Response {
  const idErr = requireId(req);
  if (idErr) return idErr;
  const item = store.get(req.params["id"]);
  if (!item) return err(404, "Item not found");
  store.delete(req.params["id"]);
  return ok({ deleted: req.params["id"] });
}

const handlers: Record<string, (req: Request) => Response> = {
  GET: handleGet,
  POST: handlePost,
  PUT: handlePut,
  DELETE: handleDelete,
};

export function handleRequest(req: Request): Response {
  const authErr = checkAuth(req);
  if (authErr) return authErr;
  const handler = handlers[req.method];
  if (!handler) return err(405, "Method not allowed");
  return handler(req);
}

import { describe, it, expect } from "vitest";
import { deepMerge } from "../../starter/deep-merge.js";

describe("deepMerge - basic merging", () => {
  it("returns a new object with all target keys", () => {
    const target = { a: 1, b: 2 };
    const source = {};
    const result = deepMerge(target, source);
    expect(result).toEqual({ a: 1, b: 2 });
  });

  it("returns a new object, not the original target", () => {
    const target = { a: 1 };
    const source = {};
    const result = deepMerge(target, source);
    expect(result).not.toBe(target);
  });

  it("merges source keys onto target", () => {
    const target = { a: 1 };
    const source = { b: 2 };
    const result = deepMerge(target, source);
    expect(result).toEqual({ a: 1, b: 2 });
  });

  it("source values overwrite target values for primitives", () => {
    const target = { a: 1, b: "old" };
    const source = { b: "new" };
    const result = deepMerge(target, source);
    expect(result.b).toBe("new");
    expect(result.a).toBe(1);
  });

  it("handles empty target and empty source", () => {
    const result = deepMerge({}, {});
    expect(result).toEqual({});
  });

  it("handles empty target with source keys", () => {
    const target = {};
    const source = { x: 42 };
    const result = deepMerge(target, source);
    expect(result).toEqual({ x: 42 });
  });

  it("handles non-overlapping keys from both objects", () => {
    const target = { a: 1 };
    const source = { b: 2 };
    const result = deepMerge(target, source);
    expect(result).toEqual({ a: 1, b: 2 });
  });
});

describe("deepMerge - undefined handling", () => {
  it("skips undefined source values, preserving target value", () => {
    const target = { a: 1 };
    const source = { a: undefined };
    const result = deepMerge(target, source);
    expect(result.a).toBe(1);
  });

  it("skips undefined for keys only in source", () => {
    const target = { a: 1 };
    const source = { b: undefined };
    const result = deepMerge(target, source);
    expect(result).not.toHaveProperty("b");
    expect(result.a).toBe(1);
  });

  it("skips multiple undefined source values", () => {
    const target = { a: 1, b: 2 };
    const source = { a: undefined, b: undefined };
    const result = deepMerge(target, source);
    expect(result).toEqual({ a: 1, b: 2 });
  });
});

describe("deepMerge - null handling", () => {
  it("null in source replaces target value with null", () => {
    const target = { a: 1 };
    const source = { a: null };
    const result = deepMerge(target, source);
    expect(result.a).toBeNull();
  });

  it("null in source for nested key replaces with null", () => {
    const target = { a: { b: 1 } };
    const source = { a: null };
    const result = deepMerge(target, source);
    expect(result.a).toBeNull();
  });

  it("null in source for new key adds null value", () => {
    const target = { a: 1 };
    const source = { b: null };
    const result = deepMerge(target, source);
    expect(result.b).toBeNull();
  });
});

describe("deepMerge - nested object recursive merge", () => {
  it("merges nested objects recursively", () => {
    const target = { a: { x: 1, y: 2 } };
    const source = { a: { y: 99, z: 3 } };
    const result = deepMerge(target, source);
    expect(result.a).toEqual({ x: 1, y: 99, z: 3 });
  });

  it("does not share reference with original nested object", () => {
    const nested = { x: 1 };
    const target = { a: nested };
    const source = { a: { y: 2 } };
    const result = deepMerge(target, source);
    expect(result.a).not.toBe(nested);
  });

  it("merges deeply nested objects at multiple levels", () => {
    const target = { a: { b: { c: 1 } } };
    const source = { a: { b: { d: 2 } } };
    const result = deepMerge(target, source);
    expect(result.a.b).toEqual({ c: 1, d: 2 });
  });

  it("handles three levels of nesting", () => {
    const target = { l1: { l2: { l3: { val: "original" } } } };
    const source = { l1: { l2: { l3: { extra: "added" } } } };
    const result = deepMerge(target, source);
    expect(result.l1.l2.l3).toEqual({ val: "original", extra: "added" });
  });

  it("replaces target object with source primitive", () => {
    const target = { a: { x: 1 } };
    const source = { a: 42 };
    const result = deepMerge(target, source);
    expect(result.a).toBe(42);
  });

  it("replaces target primitive with source object", () => {
    const target = { a: 42 };
    const source = { a: { x: 1 } };
    const result = deepMerge(target, source);
    expect(result.a).toEqual({ x: 1 });
  });

  it("merges plain object with null prototype as target nested", () => {
    const nullProtoObj = Object.create(null) as Record<string, unknown>;
    nullProtoObj.x = 1;
    const target = { a: nullProtoObj };
    const source = { a: { y: 2 } };
    const result = deepMerge(target, source);
    expect(result.a).toEqual({ x: 1, y: 2 });
  });
});

describe("deepMerge - arrays", () => {
  it("replaces target array with source array entirely", () => {
    const target = { arr: [1, 2, 3] };
    const source = { arr: [4, 5] };
    const result = deepMerge(target, source);
    expect(result.arr).toEqual([4, 5]);
  });

  it("does not share array reference with source", () => {
    const sourceArr = [1, 2, 3];
    const target = { arr: [] };
    const source = { arr: sourceArr };
    const result = deepMerge(target, source);
    expect(result.arr).not.toBe(sourceArr);
  });

  it("replaces array with empty array", () => {
    const target = { arr: [1, 2, 3] };
    const source = { arr: [] };
    const result = deepMerge(target, source);
    expect(result.arr).toEqual([]);
  });

  it("adds new array key from source", () => {
    const target = {};
    const source = { arr: [1, 2] };
    const result = deepMerge(target, source);
    expect(result.arr).toEqual([1, 2]);
  });

  it("replaces target primitive with source array", () => {
    const target = { a: 1 };
    const source = { a: [1, 2, 3] };
    const result = deepMerge(target, source);
    expect(result.a).toEqual([1, 2, 3]);
  });

  it("handles nested arrays within arrays", () => {
    const target = { arr: [[1, 2], [3, 4]] };
    const source = { arr: [[5, 6]] };
    const result = deepMerge(target, source);
    expect(result.arr).toEqual([[5, 6]]);
  });

  it("does not merge target array with source array", () => {
    const target = { arr: [1, 2, 3] };
    const source = { arr: [10] };
    const result = deepMerge(target, source);
    expect(result.arr).toHaveLength(1);
    expect(result.arr[0]).toBe(10);
  });
});

describe("deepMerge - Date handling", () => {
  it("clones Date objects from source", () => {
    const sourceDate = new Date("2024-01-15");
    const target = {};
    const source = { date: sourceDate };
    const result = deepMerge(target, source);
    expect(result.date).toEqual(sourceDate);
    expect(result.date).not.toBe(sourceDate);
  });

  it("cloned Date has same time value", () => {
    const sourceDate = new Date(1700000000000);
    const target = {};
    const source = { date: sourceDate };
    const result = deepMerge(target, source);
    expect((result.date as Date).getTime()).toBe(sourceDate.getTime());
  });

  it("modifying source date after merge does not affect result", () => {
    const sourceDate = new Date("2024-01-15");
    const target = {};
    const source = { date: sourceDate };
    const result = deepMerge(target, source);
    const originalTime = (result.date as Date).getTime();
    sourceDate.setFullYear(2099);
    expect((result.date as Date).getTime()).toBe(originalTime);
  });

  it("replaces target Date with source Date cloned", () => {
    const targetDate = new Date("2020-01-01");
    const sourceDate = new Date("2024-06-15");
    const target = { date: targetDate };
    const source = { date: sourceDate };
    const result = deepMerge(target, source);
    expect((result.date as Date).getTime()).toBe(sourceDate.getTime());
    expect(result.date).not.toBe(sourceDate);
    expect(result.date).not.toBe(targetDate);
  });

  it("handles Date nested in object", () => {
    const d = new Date("2024-03-10");
    const target = { meta: { created: new Date("2020-01-01") } };
    const source = { meta: { created: d } };
    const result = deepMerge(target, source);
    expect((result.meta as { created: Date }).created.getTime()).toBe(d.getTime());
    expect((result.meta as { created: Date }).created).not.toBe(d);
  });
});

describe("deepMerge - Symbol keys", () => {
  it("merges symbol keys from source", () => {
    const sym = Symbol("test");
    const target = {};
    const source = { [sym]: "value" };
    const result = deepMerge(target, source);
    expect(result[sym]).toBe("value");
  });

  it("preserves symbol keys from target", () => {
    const sym = Symbol("key");
    const target = { [sym]: "original" };
    const source = {};
    const result = deepMerge(target, source);
    expect(result[sym]).toBe("original");
  });

  it("overwrites target symbol key with source symbol key", () => {
    const sym = Symbol("key");
    const target = { [sym]: "old" };
    const source = { [sym]: "new" };
    const result = deepMerge(target, source);
    expect(result[sym]).toBe("new");
  });

  it("skips symbol with undefined value", () => {
    const sym = Symbol("key");
    const target = { [sym]: "preserved" };
    const source = { [sym]: undefined };
    const result = deepMerge(target, source);
    expect(result[sym]).toBe("preserved");
  });

  it("sets symbol key to null from source", () => {
    const sym = Symbol("key");
    const target = { [sym]: "value" };
    const source = { [sym]: null };
    const result = deepMerge(target, source);
    expect(result[sym]).toBeNull();
  });

  it("handles multiple symbol keys", () => {
    const sym1 = Symbol("a");
    const sym2 = Symbol("b");
    const target = { [sym1]: 1 };
    const source = { [sym2]: 2 };
    const result = deepMerge(target, source);
    expect(result[sym1]).toBe(1);
    expect(result[sym2]).toBe(2);
  });
});

describe("deepMerge - prototype pollution protection", () => {
  it("ignores __proto__ key in source", () => {
    const target = { a: 1 };
    const malicious = JSON.parse('{"__proto__": {"polluted": true}}');
    deepMerge(target, malicious);
    expect(({} as Record<string, unknown>).polluted).toBeUndefined();
  });

  it("does not pollute Object prototype via __proto__", () => {
    const target = {};
    const source: Record<string, unknown> = {};
    Object.defineProperty(source, "__proto__", {
      value: { polluted: true },
      enumerable: true,
      configurable: true,
      writable: true,
    });
    const result = deepMerge(target, source);
    expect((result as Record<string, unknown>).polluted).toBeUndefined();
  });

  it("ignores constructor key in source", () => {
    const target = { a: 1 };
    const source: Record<string, unknown> = { constructor: { polluted: true } };
    const result = deepMerge(target, source);
    expect(typeof result.constructor).not.toBe("object");
  });

  it("ignores prototype key in source", () => {
    const target = { a: 1 };
    const source: Record<string, unknown> = { prototype: { polluted: true } };
    deepMerge(target, source);
    expect(target.a).toBe(1);
  });

  it("skips all three forbidden keys while processing valid keys", () => {
    const target = { safe: "value" };
    const source: Record<string, unknown> = {
      __proto__: { evil: true },
      constructor: { evil: true },
      prototype: { evil: true },
      safe: "overwritten",
    };
    const result = deepMerge(target, source);
    expect(result.safe).toBe("overwritten");
    expect(({} as Record<string, unknown>).evil).toBeUndefined();
  });

  it("symbol named like forbidden string is NOT filtered", () => {
    const sym = Symbol("__proto__");
    const target = {};
    const source = { [sym]: "allowed" };
    const result = deepMerge(target, source);
    expect(result[sym]).toBe("allowed");
  });
});

describe("deepMerge - non-plain object values", () => {
  it("assigns class instance by reference", () => {
    class Foo {
      val = 1;
    }
    const instance = new Foo();
    const target = { a: "old" };
    const source = { a: instance };
    const result = deepMerge(target, source);
    expect(result.a).toBe(instance);
  });

  it("does not recursively merge when source is class instance", () => {
    class Foo {
      val = 1;
    }
    const instance = new Foo();
    const target = { a: { val: 99, extra: "kept?" } };
    const source = { a: instance };
    const result = deepMerge(target, source);
    expect(result.a).toBe(instance);
    expect((result.a as Foo).val).toBe(1);
  });

  it("assigns RegExp by reference", () => {
    const re = /test/gi;
    const target = {};
    const source = { pattern: re };
    const result = deepMerge(target, source);
    expect(result.pattern).toBe(re);
  });
});

describe("deepMerge - immutability", () => {
  it("does not mutate the target object", () => {
    const target = { a: 1, b: { c: 2 } };
    const source = { b: { d: 3 } };
    const targetCopy = JSON.parse(JSON.stringify(target));
    deepMerge(target, source);
    expect(target).toEqual(targetCopy);
  });

  it("does not mutate the source object", () => {
    const target = { a: 1 };
    const source = { b: { x: 10 } };
    const sourceCopy = JSON.parse(JSON.stringify(source));
    deepMerge(target, source);
    expect(source).toEqual(sourceCopy);
  });
});

describe("deepMerge - type variety", () => {
  it("handles boolean false as source value", () => {
    const result = deepMerge({ a: true }, { a: false });
    expect(result.a).toBe(false);
  });

  it("handles number 0 as source value", () => {
    const result = deepMerge({ a: 99 }, { a: 0 });
    expect(result.a).toBe(0);
  });

  it("handles empty string as source value", () => {
    const result = deepMerge({ a: "hello" }, { a: "" });
    expect(result.a).toBe("");
  });

  it("handles NaN as source value", () => {
    const result = deepMerge({ a: 1 }, { a: NaN });
    expect(result.a).toBeNaN();
  });

  it("handles Infinity as source value", () => {
    const result = deepMerge({ a: 1 }, { a: Infinity });
    expect(result.a).toBe(Infinity);
  });

  it("merges object with multiple value types", () => {
    const target = { str: "old", num: 0, bool: false, arr: [1] };
    const source = { str: "new", num: 42, bool: true, arr: [2, 3] };
    const result = deepMerge(target, source);
    expect(result).toEqual({ str: "new", num: 42, bool: true, arr: [2, 3] });
  });
});
